import json
from kafka import KafkaConsumer
from functools import wraps

# Load configuration from environment variables or a file
KAFKA_BOOTSTRAP_SERVERS = 'localhost:9092'
TOPIC_NAME = 'financial_transactions'

# Define a decorator to register message handlers dynamically
def register_message_handler(func):
    @wraps(func)
    def wrapper(message, *args, **kwargs):
        return func(message, *args, **kwargs)
    return wrapper

class TransactionProcessor:
    def __init__(self):
        self.consumer = KafkaConsumer(
            TOPIC_NAME,
            bootstrap_servers=KAFKA_BOOTSTRAP_SERVERS,
            group_id='transaction_processor',
            auto_offset_reset='latest'
        )

    @register_message_handler
    def process_transaction(message):
        transaction_data = json.loads(message.value)
        # Execute business logic based on message content
        if transaction_data['type'] == 'deposit':
            self.deposit(transaction_data)
        elif transaction_data['type'] == 'withdrawal':
            self.withdraw(transaction_data)

    def deposit(self, transaction_data):
        # Implement deposit logic here
        print(f'Depositing {transaction_data["amount"]} into account {transaction_data["account_id"]}')

    def withdraw(self, transaction_data):
        # Implement withdrawal logic here
        print(f'Withdrawing {transaction_data["amount"]} from account {transaction_data["account_id"]}')

if __name__ == '__main__':
    processor = TransactionProcessor()
    for message in processor.consumer:
        processor.process_transaction(message)